import{_ as a,o,c as t,aA as s}from"./chunks/framework.CPxl66na.js";const p=JSON.parse('{"title":"Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md","lastUpdated":null}'),r={name:"glossary.md"};function c(i,e,n,d,l,h){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="Glossary" tabindex="-1">Glossary <a class="header-anchor" href="#Glossary" aria-label="Permalink to &quot;Glossary {#Glossary}&quot;">​</a></h1><h2 id="Account" tabindex="-1">Account <a class="header-anchor" href="#Account" aria-label="Permalink to &quot;Account {#Account}&quot;">​</a></h2><p><code>Account</code> is Fastback&#39;s central state object. It owns a <code>CashLedger</code> (<code>acc.ledger</code>) for cash assets, balances, equities, and margin vectors, plus open positions, executed trades, and order/trade sequence counters.</p><h2 id="Order" tabindex="-1">Order <a class="header-anchor" href="#Order" aria-label="Permalink to &quot;Order {#Order}&quot;">​</a></h2><p>An <code>Order</code> encapsulates an instruction to trade an instrument at a specific time, price, and quantity, with optional <code>take_profit</code> and <code>stop_loss</code> levels. Orders translate into trades through <code>fill_order!</code>.</p><h2 id="Trade" tabindex="-1">Trade <a class="header-anchor" href="#Trade" aria-label="Permalink to &quot;Trade {#Trade}&quot;">​</a></h2><p>A <code>Trade</code> records the actual execution of an order, including fill price, filled and remaining quantity, realized quantity, gross additive fill P&amp;L in settlement currency (<code>fill_pnl_settle</code>), commission (<code>commission_settle</code>), settlement cash movement (<code>cash_delta_settle</code>), and the pre-trade position state. Trades accumulate in <code>Account.trades</code>.</p><h2 id="Position" tabindex="-1">Position <a class="header-anchor" href="#Position" aria-label="Permalink to &quot;Position {#Position}&quot;">​</a></h2><p>A <code>Position</code> maintains the net exposure for an instrument using a weighted-average cost basis. It stores the average prices, quantity, and unrealized P&amp;L caches (<code>pnl_quote</code>, <code>pnl_settle</code>). For principal-exchange instruments, <code>pnl_settle</code> includes both quote-price move and FX translation versus <code>avg_entry_price_settle</code>. Positions are stored in <code>Account.positions</code>.</p><h2 id="InstrumentSpec" tabindex="-1">InstrumentSpec <a class="header-anchor" href="#InstrumentSpec" aria-label="Permalink to &quot;InstrumentSpec {#InstrumentSpec}&quot;">​</a></h2><p><code>InstrumentSpec</code> holds immutable contract metadata: symbols, contract kind, settlement style, margin settings, lifecycle (<code>start_time</code>, <code>expiry</code>), and multiplier. Build specs with <code>InstrumentSpec(...)</code> or convenience constructors like <code>spot_instrument</code>, then register them with an account.</p><h2 id="Instrument" tabindex="-1">Instrument <a class="header-anchor" href="#Instrument" aria-label="Permalink to &quot;Instrument {#Instrument}&quot;">​</a></h2><p><code>Instrument</code> is the account-bound handle returned by <code>register_instrument!</code>. It contains per-account indices (<code>index</code>, <code>quote_cash_index</code>, <code>settle_cash_index</code>, <code>margin_cash_index</code>) and references its <code>InstrumentSpec</code> metadata.</p><h3 id="Spot-on-Margin" tabindex="-1">Spot on Margin <a class="header-anchor" href="#Spot-on-Margin" aria-label="Permalink to &quot;Spot on Margin {#Spot-on-Margin}&quot;">​</a></h3><p>A principal-exchange spot instrument with an explicit margin requirement (percent-notional or fixed-per-contract) represents &quot;spot on margin&quot;. Leveraged longs/shorts post margin, and shorts can accrue borrow fees via <code>short_borrow_rate</code> (borrow-fee clocks are tracked per position and aligned to fills). For <code>PercentNotional</code>, margin parameters are equity fractions of notional (IMR/MMR-style), not collateral-inclusive ratios. Short-sale proceeds treatment for interest accrual is broker-driven through <code>broker_short_proceeds_rates</code> (exclude fraction + optional rebate rate).</p><h2 id="Base-Asset" tabindex="-1">Base Asset <a class="header-anchor" href="#Base-Asset" aria-label="Permalink to &quot;Base Asset {#Base-Asset}&quot;">​</a></h2><p>The base asset represents the tradable quantity of an instrument (e.g. shares, contracts, coins). Instruments define their base symbol, tick size, min/max quantity, and display precision via <code>base_symbol</code>, <code>base_tick</code>, <code>base_min</code>, <code>base_max</code>, and <code>base_digits</code>.</p><h2 id="Price" tabindex="-1">Price <a class="header-anchor" href="#Price" aria-label="Permalink to &quot;Price {#Price}&quot;">​</a></h2><p><code>Price</code> is a type alias for <code>Float64</code> used for quote-currency values—trade prices, commissions, P&amp;L figures, and so on. Quote precision and tick sizes are instrument-defined.</p><h2 id="Quantity" tabindex="-1">Quantity <a class="header-anchor" href="#Quantity" aria-label="Permalink to &quot;Quantity {#Quantity}&quot;">​</a></h2><p><code>Quantity</code> is a type alias for <code>Float64</code> describing position or order size. Positive quantities represent long exposure; negative quantities represent short exposure across orders, trades, and positions.</p><h2 id="Exposure" tabindex="-1">Exposure <a class="header-anchor" href="#Exposure" aria-label="Permalink to &quot;Exposure {#Exposure}&quot;">​</a></h2><p>Exposure is the signed quantity of an open position. Helper predicates such as <code>has_exposure</code>, <code>is_long</code>, <code>is_short</code>, and <code>trade_dir</code> determine exposure state for <code>Position</code>s and <code>Account</code>s.</p><h2 id="Fill" tabindex="-1">Fill <a class="header-anchor" href="#Fill" aria-label="Permalink to &quot;Fill {#Fill}&quot;">​</a></h2><p>A fill is the execution of an order (whole or partial). <code>fill_order!</code> creates a <code>Trade</code> with the fill price, fill quantity, remaining quantity, and realized P&amp;L.</p><h2 id="Commission" tabindex="-1">Commission <a class="header-anchor" href="#Commission" aria-label="Permalink to &quot;Commission {#Commission}&quot;">​</a></h2><p>Commission is specified by the active broker profile and converted from quote to settlement currency on each fill, then stored on the trade as <code>commission_settle</code>. This amount is applied to balances, equities, and realized P&amp;L in settlement units.</p><h2 id="Realized-P-and-L" tabindex="-1">Realized P&amp;L <a class="header-anchor" href="#Realized-P-and-L" aria-label="Permalink to &quot;Realized P&amp;amp;L {#Realized-P-and-L}&quot;">​</a></h2><p><code>fill_pnl_settle</code> is gross fill-settled P&amp;L (commissions excluded).</p><p>For principal-exchange settlement, <code>fill_pnl_settle</code> equals closed-position realized P&amp;L when exposure decreases (<code>realized_qty</code>). For variation-margin settlement, it includes both open mark-to-fill settlement and reduce-basis settlement, and fills reset <code>avg_settle_price</code> to the current mark.</p><p>Commissions are separate via <code>commission_settle</code>. The actual fill cash movement is always <code>cash_delta_settle</code>; for variation margin, <code>cash_delta_settle = fill_pnl_settle - commission_settle</code>.</p><h2 id="Unrealized-P-and-L" tabindex="-1">Unrealized P&amp;L <a class="header-anchor" href="#Unrealized-P-and-L" aria-label="Permalink to &quot;Unrealized P&amp;amp;L {#Unrealized-P-and-L}&quot;">​</a></h2><p>Unrealized P&amp;L is cached on positions as <code>pnl_quote</code> and <code>pnl_settle</code>. <code>update_marks!</code> keeps these caches in sync and mirrors the resulting value change into equity. For principal-exchange cross-currency positions, <code>pnl_settle</code> includes principal FX translation from the settlement-entry basis.</p><h2 id="Trade-Direction" tabindex="-1">Trade Direction <a class="header-anchor" href="#Trade-Direction" aria-label="Permalink to &quot;Trade Direction {#Trade-Direction}&quot;">​</a></h2><p><code>TradeDir</code> is the <code>@enumx</code> representing trade direction: <code>Buy</code>, <code>Sell</code>, or <code>Null</code>. Conversion helpers such as <code>trade_dir(quantity)</code>, <code>is_long</code>, <code>is_short</code>, and <code>opposite_dir</code> provide directional logic across orders, trades, and positions.</p><h2 id="Balance" tabindex="-1">Balance <a class="header-anchor" href="#Balance" aria-label="Permalink to &quot;Balance {#Balance}&quot;">​</a></h2><p>A balance is the cash-only value associated with a <code>Cash</code> asset. Deposits, withdrawals, commissions, and realized P&amp;L update balances; floating P&amp;L from open positions does not. Access balances through <code>cash_balance(acc, cash)</code>.</p><h2 id="Equity" tabindex="-1">Equity <a class="header-anchor" href="#Equity" aria-label="Permalink to &quot;Equity {#Equity}&quot;">​</a></h2><p>Equity is the balance of a cash asset plus the unrealized P&amp;L of open positions denominated in that currency. Access equities through <code>equity(acc, cash)</code>.</p><h2 id="Cash-Asset" tabindex="-1">Cash Asset <a class="header-anchor" href="#Cash-Asset" aria-label="Permalink to &quot;Cash Asset {#Cash-Asset}&quot;">​</a></h2><p>A <code>Cash</code> object models a funding currency (USD, EUR, BTC, …) with display precision and a ledger-assigned index. <code>Cash</code> is owned by <code>CashLedger</code>. Register currencies through <code>register_cash_asset!(acc, CashSpec(:EUR))</code> to get account-owned <code>Cash</code> handles.</p><h2 id="Collector" tabindex="-1">Collector <a class="header-anchor" href="#Collector" aria-label="Permalink to &quot;Collector {#Collector}&quot;">​</a></h2><p>Collectors are lightweight recorders that capture time-series or summary statistics during a backtest. <code>periodic_collector</code>, <code>predicate_collector</code>, <code>drawdown_collector</code>, <code>portfolio_weights_collector</code>, <code>turnover_collector</code>, and helpers like <code>min_value_collector</code> are part of the collectors API and return both the collecting closure and the mutable storage.</p><p><code>turnover_collector</code> records fill-time gross traded notional in account base currency and reports turnover as <code>gross_traded_notional / (2 * equity_base_ccy(acc))</code> by default. Use <code>TurnoverMode.OneWay</code> to report <code>gross_traded_notional / equity_base_ccy(acc)</code>. Turnover is <code>NaN</code> when base-currency equity is nonpositive.</p><h2 id="Exchange-Rate" tabindex="-1">Exchange Rate <a class="header-anchor" href="#Exchange-Rate" aria-label="Permalink to &quot;Exchange Rate {#Exchange-Rate}&quot;">​</a></h2><p><code>ExchangeRates</code> converts values between cash assets using a mutable matrix of pairwise rates and implied reciprocals.</p><h2 id="Batch-Backtest" tabindex="-1">Batch Backtest <a class="header-anchor" href="#Batch-Backtest" aria-label="Permalink to &quot;Batch Backtest {#Batch-Backtest}&quot;">​</a></h2><p><code>batch_backtest</code> runs a vector of parameter sets across one backtest function, optionally multi-threaded, while reporting progress and optional callbacks.</p>',48)])])}const m=a(r,[["render",c]]);export{p as __pageData,m as default};
